CREATE TABLE IF NOT EXISTS influencer_instructions (
    id TINYINT UNSIGNED NOT NULL PRIMARY KEY,
    content_json LONGTEXT NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO configuracion_general (clave, valor, descripcion)
VALUES ('instrucciones_influencer', '0', 'Activa o desactiva el modulo publico y administrativo de Instrucciones Influencer')
ON DUPLICATE KEY UPDATE valor = VALUES(valor), descripcion = VALUES(descripcion);

INSERT INTO influencer_instructions (id, content_json)
VALUES (
    1,
    '{"menu_label":"Quiero Unirme","hero":{"badge":"Programa Influencer","title":"Convierte tu comunidad en ventas reales","lead_html":"<p>Activa tu acceso al programa Influencer y comparte tus enlaces, tus codigos y tus recomendaciones con una presentacion profesional.</p><p>Todo el proceso esta disenado para que puedas empezar rapido, vender con confianza y mantener una comunicacion clara con tu audiencia.</p>","primary_label":"Solicitar acceso","primary_url":"","secondary_label":"Ver pasos","secondary_url":"#pasos-influencer","image":""},"benefits":{"eyebrow":"Beneficios","title":"Lo que recibes al entrar al programa","intro_html":"<p>Configura una propuesta atractiva para tu comunidad y muestra de inmediato por que vale la pena unirse a tu canal de ventas.</p>","items":[{"title":"Comisiones claras","html":"<p>Trabaja con una estructura de beneficios definida para que sepas cuanto puedes generar por cada venta referida.</p>"},{"title":"Material listo para publicar","html":"<p>Comparte instrucciones, pasos y mensajes con una pagina pensada para explicar el proceso sin friccion.</p>"},{"title":"Escalado ordenado","html":"<p>Convierte tus publicaciones en un flujo constante de solicitudes, consultas y ventas mejor organizadas.</p>"}]},"steps":{"eyebrow":"Paso a paso","title":"Como funciona el ingreso","intro_html":"<p>Explica el recorrido completo en tres bloques para que cualquier creador entienda rapidamente como avanzar.</p>","items":[{"icon":"sparkles","title":"1. Envia tu solicitud","html":"<p>Comparte tus datos, tus redes y el tipo de comunidad que manejas para evaluar tu ingreso al programa Influencer.</p>"},{"icon":"megaphone","title":"2. Recibe tus recursos","html":"<p>Una vez aprobado, recibes el material, los lineamientos y la informacion comercial para comenzar a promocionar.</p>"},{"icon":"rocket","title":"3. Empieza a vender","html":"<p>Publica, comparte tu codigo y centraliza las consultas usando un mensaje y una llamada a la accion bien definidos.</p>"}]},"notes":{"eyebrow":"Notas especiales","title":"Puntos importantes antes de activar tu cuenta","intro_html":"<p>Usa este bloque para dejar condiciones, tiempos de respuesta o reglas internas con el mismo peso visual que el ejemplo.</p>","items":[{"icon":"shield","title":"Cumple las reglas del programa","html":"<p>Mantener mensajes claros, precios correctos y una comunicacion responsable protege tanto tu marca como la de la tienda.</p>"},{"icon":"gift","title":"Promociones sujetas a campanas","html":"<p>Las condiciones de bonos, activaciones o incentivos especiales pueden ajustarse segun la temporada o el objetivo comercial.</p>"},{"icon":"star","title":"Prioriza contenido con conversion","html":"<p>El programa Influencer funciona mejor cuando publicas piezas concretas, frecuentes y alineadas con la audiencia correcta.</p>"}]},"closing":{"eyebrow":"Listo para empezar","title":"Activa tu solicitud hoy","content_html":"<p>Si ya tienes comunidad, presencia en redes o una audiencia interesada en recargas, este es el momento de formalizar tu entrada al programa Influencer.</p><p>Deja tu llamada a la accion final con el texto exacto que quieras destacar.</p>","button_label":"Hablar con soporte","button_url":""},"colors":{"hero_surface":"#0F172A","hero_accent":"#22D3EE","hero_text":"#E2F8FF","benefits_surface":"#111827","steps_surface":"#172554","notes_surface":"#1F2937","closing_surface":"#0B1120","button_bg":"#F59E0B","button_text":"#111827"}}'
)
ON DUPLICATE KEY UPDATE content_json = VALUES(content_json);